class Solution:
    def shortestWay(self, source: str, target: str) -> int:
        sc, tc = Counter(source), Counter(target)
        if len(set(tc.keys()) - set(sc.keys())) > 0 : return -1
        sp, tp, count = 0, 0, 0
        while tp < len(target):
            if sp == len(source):
                sp = 0
                count +=1

            if source[sp] == target[tp]:
                tp += 1

            sp += 1

        return count+1
