#include<bits/stdc++.h>

using namespace std;

struct Node{
    Node *links[26];
    int count=0;
    bool flag;

    bool containsKey(char c){
       return (links[c-'a']!=NULL); 
    }   

    void putKey(char c,Node* node){
       links[c-'a']=node; 
    } 

    Node* get(char c){
      return links[c-'a'];  
    } 
};

class Trie {
private: Node* root;
public:
    Trie() {
        root=new Node();
    }

    void insert(string word) {
        Node* node=root;
        for(int i=0;i<word.length();i++){     
            if(!node->containsKey(word[i])){
                node->putKey(word[i],new Node());
            }
            node=node->get(word[i]);
        }
    }

    int count(string s){
        Node* node=root;
        int ans=0;
        int ind=0;
        while(ind<s.length()){
            if(!node->containsKey(s[ind])){
                if(node==root)return -1;
                ++ans;
                node=root;
            }
            else{
                node=node->get(s[ind]);
                ++ind;
            }
        }
        return ans;
    }
};

int main() {
  string s1, s2;
  cin >> s1 >> s2;

  Trie trie;
  for (int i = 0; i < s1.size(); i++) {
    trie.insert(s1.substr(i));
  }

  int ans=trie.count(s2);
  cout << ans <<endl;
  return 0;
}

